queries.sparql:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?categoryname WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasCategories ?child ; p:hasMagazines ?parent . } GROUP BY ?child }
  ?child p:categoryName ?categoryname .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Magazines } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?categoryname WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasCategories ?child ; p:hasMagazines ?parent . } GROUP BY ?child }
  ?child p:categoryName ?categoryname .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Magazines } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?magazinetitle ?categoryname WHERE {
  ?magazines_categories a :Magazines_Categories .
  ?categories a :Category .
  ?magazines_categories p:hasCategories ?categories .
  ?magazines a :Magazines .
  ?magazines_categories p:hasMagazines ?magazines .
  ?magazines p:magazineTitle ?magazinetitle .
  ?categories p:categoryName ?categoryname .
} }
}
